function getModulesForPeriod(period) {
  // All modules are Period 2 for now
  if (period === 2) return MODULES;
  return [];
}
function getModulesBySection() {
  const grouped = {};
  MODULES.forEach(m => {
    if (!grouped[m.section]) grouped[m.section] = [];
    grouped[m.section].push(m);
  });
  return MODULE_SECTIONS.map(s => ({ ...s, modules: grouped[s.id] || [] })).filter(s => s.modules.length > 0);
}

